class Solution {
    public int longestSubsequence(String s, int k) {
        int longest = 0;
        for (int i = 0; i < s.length(); i++) {
            int current = 0;
            for (int j = i; j < s.length(); j++) {
                current = (current << 1) | (s.charAt(j) - '0');
                if (current > k) {
                    break;
                }
                longest = Math.max(longest, j - i + 1);
            }
        }
        return longest;
    }
}
